export const meta = {
  name: 'genus0-routec-cleanup-manifest',
  description: 'Map the exact genus-0 / Route-C cleanup surface for T13 across blueprint tex, Lean comments, roadmap.md, WeilDivisor carve boundary, and DAG orphans',
  phases: [
    { title: 'Scout', detail: 'five read-only scouts map each surface with file:line' },
    { title: 'Synthesize', detail: 'merge into one ordered cleanup manifest' },
  ],
}

const AJC = '/home/Axel/LeanAlgebraicGeometry-Horizon/MainProjects/Algebraic-Jacobian-Challenge'
const ROOT = '/home/Axel/LeanAlgebraicGeometry-Horizon'

const FINDINGS_SCHEMA = {
  type: 'object',
  additionalProperties: false,
  required: ['findings', 'summary'],
  properties: {
    summary: { type: 'string', description: 'One-paragraph overview of what this surface contains' },
    findings: {
      type: 'array',
      items: {
        type: 'object',
        additionalProperties: false,
        required: ['file', 'line', 'classification', 'snippet', 'action'],
        properties: {
          file: { type: 'string', description: 'repo-relative or absolute path' },
          line: { type: 'integer', description: '1-indexed line (or start line of a range)' },
          endLine: { type: 'integer', description: 'end line if a range, else same as line' },
          classification: { type: 'string', enum: ['stale-dead', 'stale-prose-live-math', 'good-current-doc', 'carve-delete', 'carve-keep', 'dag-orphan', 'out-of-t13-scope'] },
          snippet: { type: 'string', description: 'short quoted text' },
          action: { type: 'string', description: 'precise recommended edit for Horizon (remove / rewrite / keep / verify)' },
        },
      },
    },
  },
}

phase('Scout')

const T13_SCOPE = "T13 write globs are: AlgebraicJacobian/Picard/*.lean, AlgebraicJacobian/Albanese/*.lean, AlgebraicJacobian/RigidityLemma.lean, AlgebraicJacobian/RiemannRoch/WeilDivisor.lean, AlgebraicJacobian/Genus0BaseObjects/*.lean (dir no longer exists), and roadmap.md (workspace root). Files OUTSIDE these globs (e.g. AbelJacobi.lean, Jacobian.lean, Genus.lean) are out-of-scope for T13 edits."

const CONTEXT = `Background: the genus-0 vs genus>0 strategy split has ALREADY been mostly retired in the Lean tree. Genus0BaseObjects/*, AbelianVarietyRigidity.lean, genusZeroWitness/positiveGenusWitness are deleted; Jacobian C := (jacobianWitness C).J is uniform (no dite). 'Route C' means a paused coherent-chi / Riemann-Roch route: (a) a DEAD genus-0-base usage (genusZero_curve_iso_P1, RR->P1) that is dead weight, AND (b) a LIVE alternative-endgame usage for the 5 headline Quot representability decls (coherent chi substrate). Distinguish these two. Report file:line for everything. Do NOT edit any files — read only. Return raw structured data.`

const scouts = [
  {
    label: 'blueprint-tex',
    prompt: `${CONTEXT}\n\nSCOUT TASK: Map genus-0 / Route-C content in the AJC blueprint LaTeX SOURCE under ${AJC}/blueprint/src/ (chapters/*.tex, content.tex, web.tex, print.tex). Search for: genus 0, genus-0, genus zero, Genus0BaseObjects, genusZero_curve_iso_P1, Route C, Route-C, BareScheme, projective line base case. For each hit give the exact file, line, the \\label/node name if inside a \\begin{definition|theorem|lemma}, the snippet, and classify: is it (stale-dead) referencing deleted Lean decls / removed chapters, (stale-prose-live-math) stale narrative wrapping still-valid math, or (good-current-doc). Also: check whether any chapter is entirely about the removed genus-0 base (a whole-chapter removal candidate), and whether ${AJC}/blueprint/src/content.tex still \\input{}s any removed genus-0 chapter. Also check ${AJC}/blueprint/web/ for stale generated HTML like chap-Genus0BaseObjects_Cross01Substrate.html (classification dag-orphan). Give a precise action per finding.`,
  },
  {
    label: 'lean-comments',
    prompt: `${CONTEXT}\n\n${T13_SCOPE}\n\nSCOUT TASK: Map genus-0 / Route-C mentions in Lean SOURCE comments/docstrings across ${AJC}/AlgebraicJacobian/**/*.lean (recursively). Search: genus 0, genus-0, genus zero, Genus0BaseObjects, genusZero, Route C, Route-C, dite.*genus, STRATEGY.md, RationalCurveIso, RiemannRoch_RationalIsoP1. For EACH hit: file, line, snippet, and classify (stale-dead / stale-prose-live-math / good-current-doc / out-of-t13-scope). CRITICAL: mark each finding out-of-t13-scope if its file is NOT one of the T13 write globs. Note especially: does any file still have ACTIVE genus-branching CODE (not just comments) — a dite or if on genus = 0? And flag broken pointers (e.g. references to a nonexistent .archon/STRATEGY.md or blueprint/src/chapters/Genus.tex). Give a precise action per finding (remove comment / rewrite prose / keep / verify-live).`,
  },
  {
    label: 'roadmap-md',
    prompt: `${CONTEXT}\n\nSCOUT TASK: Read ${ROOT}/roadmap.md in full. Find EVERY line that mentions genus-0, Genus0BaseObjects, BareScheme, Route C / Route-C, or the 'RiemannRoch extraction obsolete' / Weil-divisor remnant claims. For each: line number, exact snippet, and CROSS-CHECK the claim against reality — e.g. does the file/dir it names actually exist under ${AJC}/AlgebraicJacobian/ ? (Genus0BaseObjects/BareScheme.lean, Genus0BaseObjects/Points.lean — verify existence with ls/find). Classify stale-dead if the line asserts existence/status of something deleted. Give the precise rewrite or deletion each line needs so roadmap.md honestly reflects the uniform-genus tree. Also note any OTHER internal inconsistencies you spot in roadmap.md while reading (paused/obsolete strategies still listed as active).`,
  },
  {
    label: 'weildivisor-carve',
    prompt: `${CONTEXT}\n\nSCOUT TASK: Determine the EXACT carve boundary in ${AJC}/AlgebraicJacobian/RiemannRoch/WeilDivisor.lean (1334 lines). Two masters: (KEEP substrate) Scheme.PrimeDivisor, Scheme.WeilDivisor type, restrictToOpen/ofOpen/equivOpen/stalkIso, Ring.* ord helpers, functionFieldIso, order, IsRegularInCodimensionOne, RationalMap.order_* lemmas, functionFieldIso_compat, order_eq_order_restrict, rationalMap_order_finite_support — these are the codim-1 valuation substrate imported by Albanese/CodimOneExtension.lean. (DELETE Route-C dead weight) the degree / degree_hom / ofClosedPoint / positivePart / principal_degree_zero / RR->P1 block framed around genusZero_curve_iso_P1, plus the file HEADER prose that frames the whole file around genusZero_curve_iso_P1 and RiemannRoch_RationalIsoP1.tex, plus the '-- Route C PAUSE' regions and their sorries. Give: (1) precise line ranges to DELETE (carve-delete) with the decl names, (2) precise line ranges/decls to KEEP (carve-keep), (3) which sorries fall in the delete block vs keep block (count each), (4) EXACTLY which declarations in ${AJC}/AlgebraicJacobian/Albanese/CodimOneExtension.lean consume the WeilDivisor substrate (grep its code, not comments), so Horizon knows the minimal keep-set. Warn clearly that a wholesale file delete breaks the CodimOneExtension build.`,
  },
  {
    label: 'dag-orphans',
    prompt: `${CONTEXT}\n\nSCOUT TASK: Investigate blueprint DAG health for genus-0/Route-C orphans. Run: '$HORIZON_BIN' leandag --json (or without --json) to get the AJC dangling/isolated node list — the environment var HORIZON_BIN is an absolute path to the horizon CLI (try /home/Axel/.archon-venv/bin/horizon if the var is unset). The AJC blueprint summary reported 2 dangling nodes. Identify those 2 dangling nodes by name/label, and say whether either relates to genus-0 / Route-C / removed material. Also inspect ${AJC}/blueprint/web/ (ls) for stale generated HTML chapters whose .tex source no longer exists (e.g. Genus0BaseObjects). Also grep the blueprint JSON at ${ROOT}/.archon-horizon/blueprints/Algebraic-Jacobian-Challenge.json for any node id/label containing genus0, genusZero, routeC, bareScheme, projectiveLineBar. Report each with classification dag-orphan or good-current-doc and a precise action.`,
  },
]

const results = await parallel(scouts.map(s => () =>
  agent(s.prompt, { label: s.label, phase: 'Scout', schema: FINDINGS_SCHEMA, agentType: 'general-purpose' })
    .then(r => ({ scout: s.label, ...r }))
))

phase('Synthesize')

const merged = results.filter(Boolean)
const synth = await agent(
  `You are Ground synthesizing a T13 cleanup manifest for the Horizon agent. Below are five read-only scout reports (JSON) mapping the genus-0 / Route-C cleanup surface across blueprint tex, Lean comments, roadmap.md, the WeilDivisor carve boundary, and the DAG.\n\n${JSON.stringify(merged, null, 1)}\n\nProduce a SINGLE ordered, deduplicated cleanup manifest as Markdown for Horizon, with these sections:\n1. **In-scope edits** (grouped by file, each an actionable file:line -> edit), covering roadmap.md, RigidityLemma.lean, WeilDivisor.lean carve (explicit keep vs delete line ranges + sorry counts + the CodimOneExtension keep-set), and any blueprint .tex chapters/content.tex.\n2. **Out-of-T13-scope residue** (AbelJacobi.lean / Jacobian.lean / Genus.lean etc.) — list precisely so the human can decide whether to widen scope; distinguish stale-dead comments from good-current-docs that should stay.\n3. **Dependency traps & correctness cautions** — the WeilDivisor-breaks-CodimOneExtension trap, the Route-C ambiguity (dead genus-0-base vs live coherent-chi endgame), any active genus-branching CODE still present, broken file pointers, stale generated web HTML.\n4. **Verification checklist** — the minimal build/kernel checks Horizon should run after the carve (which import chain to rebuild).\nBe precise with paths and line numbers. Flag any contradictions BETWEEN the scout reports. Keep it tight; this is a manifest, not prose. Return the Markdown as your final text.`,
  { label: 'synthesize-manifest', phase: 'Synthesize' }
)

return { manifest: synth, scoutSummaries: merged.map(m => ({ scout: m.scout, summary: m.summary, count: (m.findings || []).length })) }
